import React from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import './App.css';
export default function App() {
  return (
    <Router>
      <div>
        <nav>
          <ul>
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/login">Login</Link>
            </li>
            <li>
              <Link to="/reset">Reset</Link>
            </li>
            <li>
              <Link to="/dashboard">Dashboard</Link>
            </li>
          </ul>
        </nav>

        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/reset" element={<PasswordReset />} />
          <Route path="/dashboard" element={<Dashboard />} /> {/* Исправлено здесь */}
        </Routes>
      </div>
    </Router>
  );
}

function Home() {
  return <h2 style={{textAlign: 'center'}}>Home</h2>;
}

function Login() {
  return (
    <div className="page-content">
      <h2 style={{textAlign: 'center', color: 'white'}}>Login</h2>
      <div style={{marginBottom: '20px'}}>
        <input placeholder="Email" />
        <input placeholder="Password" />
      </div>
      <div className="button">
        <div className="text">Войти</div>
        <div className="progress-bar"></div>
        <svg viewBox="0 0 32 32">
          <path className="check" d="M27 9L13 23 5 15" />
        </svg>
      </div>
    </div>
  );
}

function PasswordReset() {
  return <h2 style={{textAlign: 'center'}}>Password Reset</h2>;
}

function Dashboard() {
  return <h2 style={{textAlign: 'center'}}>Dashboard</h2>;
}
